package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.bind.TreeTypeAdapter;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.lang.reflect.Type;
import java.util.List;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void registerTypeHierarchyAdapter_withNullBaseType_throwsNullPointerException() {
    assertThrows(NullPointerException.class, () -> gsonBuilder.registerTypeHierarchyAdapter(null, new JsonSerializer<Object>() {
      @Override
      public JsonElement serialize(Object src, Type typeOfSrc, JsonSerializationContext context) {
        return null;
      }
    }));
  }

  @Test
  void registerTypeHierarchyAdapter_withInvalidTypeAdapter_throwsIllegalArgumentException() {
    Object invalidAdapter = new Object();
    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> gsonBuilder.registerTypeHierarchyAdapter(String.class, invalidAdapter));
    assertTrue(thrown.getMessage().contains("typeAdapter"));
  }

  @Test
  void registerTypeHierarchyAdapter_withJsonSerializer_addsToHierarchyFactories() throws Exception {
    Class<?> baseType = Number.class;
    JsonSerializer<?> serializer = mock(JsonSerializer.class);

    GsonBuilder builder = new GsonBuilder();

    try (MockedStatic<TreeTypeAdapter> mockedTreeTypeAdapter = Mockito.mockStatic(TreeTypeAdapter.class)) {
      TreeTypeAdapter.TreeTypeAdapterFactory factoryMock = mock(TreeTypeAdapter.TreeTypeAdapterFactory.class);
      mockedTreeTypeAdapter.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, serializer)).thenReturn(factoryMock);

      GsonBuilder returned = builder.registerTypeHierarchyAdapter(baseType, serializer);
      assertSame(builder, returned);

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      List<?> hierarchyFactories = (List<?>) hierarchyFactoriesField.get(builder);
      assertTrue(hierarchyFactories.contains(factoryMock));

      // factories list should remain empty
      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      List<?> factories = (List<?>) factoriesField.get(builder);
      assertTrue(factories.isEmpty());
    }
  }

  @Test
  void registerTypeHierarchyAdapter_withJsonDeserializer_addsToHierarchyFactories() throws Exception {
    Class<?> baseType = Number.class;
    JsonDeserializer<?> deserializer = mock(JsonDeserializer.class);

    GsonBuilder builder = new GsonBuilder();

    try (MockedStatic<TreeTypeAdapter> mockedTreeTypeAdapter = Mockito.mockStatic(TreeTypeAdapter.class)) {
      TreeTypeAdapter.TreeTypeAdapterFactory factoryMock = mock(TreeTypeAdapter.TreeTypeAdapterFactory.class);
      mockedTreeTypeAdapter.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, deserializer)).thenReturn(factoryMock);

      GsonBuilder returned = builder.registerTypeHierarchyAdapter(baseType, deserializer);
      assertSame(builder, returned);

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      List<?> hierarchyFactories = (List<?>) hierarchyFactoriesField.get(builder);
      assertTrue(hierarchyFactories.contains(factoryMock));

      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      List<?> factories = (List<?>) factoriesField.get(builder);
      assertTrue(factories.isEmpty());
    }
  }

  @Test
  void registerTypeHierarchyAdapter_withTypeAdapter_addsToFactories() throws Exception {
    Class<?> baseType = Number.class;
    @SuppressWarnings("unchecked")
    TypeAdapter<?> typeAdapter = mock(TypeAdapter.class);

    GsonBuilder builder = new GsonBuilder();

    try (MockedStatic<TypeAdapters> mockedTypeAdapters = Mockito.mockStatic(TypeAdapters.class)) {
      TypeAdapterFactory factoryMock = mock(TypeAdapterFactory.class);
      mockedTypeAdapters.when(() -> TypeAdapters.newTypeHierarchyFactory(baseType, typeAdapter)).thenReturn(factoryMock);

      GsonBuilder returned = builder.registerTypeHierarchyAdapter(baseType, typeAdapter);
      assertSame(builder, returned);

      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      List<?> factories = (List<?>) factoriesField.get(builder);
      assertTrue(factories.contains(factoryMock));

      // hierarchyFactories should remain empty
      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      List<?> hierarchyFactories = (List<?>) hierarchyFactoriesField.get(builder);
      assertTrue(hierarchyFactories.isEmpty());
    }
  }

  @Test
  void registerTypeHierarchyAdapter_withJsonSerializerAndTypeAdapter_addsToBothLists() throws Exception {
    Class<?> baseType = Number.class;
    JsonSerializer<?> serializer = mock(JsonSerializer.class);
    @SuppressWarnings("unchecked")
    TypeAdapter<?> typeAdapter = mock(TypeAdapter.class);

    // Create a proxy object that implements both interfaces to pass as typeAdapter
    Object combinedAdapter = new Object() implements JsonSerializer<Object>, TypeAdapter<Object> {
      @Override
      public JsonElement serialize(Object src, Type typeOfSrc, JsonSerializationContext context) {
        return null;
      }
      @Override
      public Object read(JsonReader in) {
        return null;
      }
      @Override
      public void write(JsonWriter out, Object value) {
      }
    };

    // But since the method checks instanceof, we cannot pass the combinedAdapter easily.
    // Instead, test separately with two calls.

    // First call with serializer
    GsonBuilder builder = new GsonBuilder();

    try (MockedStatic<TreeTypeAdapter> mockedTreeTypeAdapter = Mockito.mockStatic(TreeTypeAdapter.class)) {
      TreeTypeAdapter.TreeTypeAdapterFactory factoryMock = mock(TreeTypeAdapter.TreeTypeAdapterFactory.class);
      mockedTreeTypeAdapter.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, serializer)).thenReturn(factoryMock);

      builder.registerTypeHierarchyAdapter(baseType, serializer);

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      List<?> hierarchyFactories = (List<?>) hierarchyFactoriesField.get(builder);
      assertTrue(hierarchyFactories.contains(factoryMock));
    }

    // Second call with typeAdapter
    try (MockedStatic<TypeAdapters> mockedTypeAdapters = Mockito.mockStatic(TypeAdapters.class)) {
      TypeAdapterFactory factoryMock2 = mock(TypeAdapterFactory.class);
      mockedTypeAdapters.when(() -> TypeAdapters.newTypeHierarchyFactory(baseType, typeAdapter)).thenReturn(factoryMock2);

      builder.registerTypeHierarchyAdapter(baseType, typeAdapter);

      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      List<?> factories = (List<?>) factoriesField.get(builder);
      assertTrue(factories.contains(factoryMock2));
    }
  }
}
